import{c as r,Z as n,Q as i,j as o,g as a,n as l,o as s,m as h}from"./chunks/framework.qjzPVSkb.js";const F=JSON.parse('{"title":"RLHF","description":"基于人类反馈的强化学习——用人类偏好数据训练奖励模型，引导 LLM 输出更符合人类期望的内容","frontmatter":{"title":"RLHF","description":"基于人类反馈的强化学习——用人类偏好数据训练奖励模型，引导 LLM 输出更符合人类期望的内容","difficulty":"advanced"},"headers":[],"relativePath":"terms/rlhf.md","filePath":"terms/rlhf.md"}'),d={name:"terms/rlhf.md"};function g(c,e,f,u,m,p){const t=n("DifficultyBadge");return i(),o("div",null,[e[0]||(e[0]=a("h1",{id:"rlhf",tabindex:"-1"},[l("RLHF "),a("a",{class:"header-anchor",href:"#rlhf","aria-label":'Permalink to "RLHF"'},"​")],-1)),s(t,{level:"advanced"}),e[1]||(e[1]=h('<h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>RLHF（Reinforcement Learning from Human Feedback，基于人类反馈的强化学习）是一种训练方法，它先用<strong>人类偏好标注数据</strong>训练一个&quot;奖励模型&quot;来判断回答的好坏，再用强化学习算法（通常是 PPO）<strong>微调 LLM</strong>，使模型输出更符合人类的价值观、偏好和安全要求。ChatGPT 的成功在很大程度上归功于 RLHF。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>训练一个实习记者写新闻稿。第一阶段，让他读海量新闻稿（预训练），他学会了句子结构和常见表达。第二阶段，给他具体的任务和参考范文训练（监督微调 / SFT），他能写出基本格式正确的稿子了。但问题来了——编辑发现他有时会写偏激观点或过于啰嗦。于是第三阶段，编辑开始给每篇稿件打分（人类反馈），并且告诉他&quot;简明扼要 +3 分&quot;&quot;过度修饰 -1 分&quot;&quot;客观中立 +2 分&quot;（奖励模型）。记者根据这些反馈不断调整写作风格，最终写出让编辑满意的稿子——这就是 RLHF 的过程。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>RLHF 通常包含三个训练阶段：</p><ol><li><strong>监督微调（SFT, Supervised Fine-Tuning）</strong>：用高质量的&quot;指令-回答&quot;对微调预训练模型，让模型学会遵循指令。这是 RLHF 的基础</li><li><strong>训练奖励模型（RM, Reward Model）</strong>：让人类标注员对同一问题的多个回答进行偏好排序（如 A &gt; B &gt; C），用这些数据训练一个奖励模型。奖励模型的责任是：给定一个回答，预测它会得到多高的人类评分</li><li><strong>强化学习微调（RL Fine-Tuning）</strong>：使用 <strong>PPO（Proximal Policy Optimization）</strong> 算法，以奖励模型的输出作为奖励信号，微调 SFT 模型。同时引入 <strong>KL 散度惩罚</strong>，防止模型偏离 SFT 模型太远而导致语言质量崩塌</li></ol><p>RLHF 的核心价值：</p><ul><li><strong>对齐（Alignment）</strong>：让模型行为与人类价值观一致</li><li><strong>安全性</strong>：减少有害、偏见、误导性输出</li><li><strong>有用性</strong>：让回答更直接、更符合用户实际需求</li></ul><p>RLHF 的替代方案也在快速发展，包括 <strong>DPO（Direct Preference Optimization）</strong>——直接基于偏好数据优化而无需单独训练奖励模型，更简洁高效。以及 <strong>RLVR（Reinforcement Learning with Verifiable Rewards）</strong>——用数学/代码等可自动验证的任务提供奖励信号，避免了昂贵的人类标注。</p><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/fine-tuning.html">微调 (Fine-tuning)</a> —— SFT 是 RLHF 的第一阶段</li><li><a href="/ai-knowledge/terms/llm.html">大语言模型 (LLM)</a> —— RLHF 是现代 LLM 对齐训练的标准方法</li><li><a href="/ai-knowledge/terms/training-inference.html">训练 / 推理</a> —— RLHF 属于训练阶段的优化</li></ul><h2 id="快速记忆" tabindex="-1">快速记忆 <a class="header-anchor" href="#快速记忆" aria-label="Permalink to &quot;快速记忆&quot;">​</a></h2><p>RLHF = 用人类的喜好给模型打分。好比训练一条狗——做对了给零食（奖励），做错了不搭理。只不过这里训练的是几十亿参数的神经网络。</p><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>InstructGPT 论文：<a href="https://arxiv.org/abs/2203.02155" target="_blank" rel="noreferrer">Training language models to follow instructions with human feedback</a> —— RLHF 在 ChatGPT 中的应用</li><li>DPO 论文：<a href="https://arxiv.org/abs/2305.18290" target="_blank" rel="noreferrer">Direct Preference Optimization</a> —— RLHF 的简化替代方案</li><li>Anthropic 的 RLHF 实践：<a href="https://www.anthropic.com/index/training-helpful-and-harmless-assistant" target="_blank" rel="noreferrer">Training a Helpful and Harmless Assistant</a></li><li>学习建议：先理解监督微调的基本流程，再逐步学习奖励模型训练和 PPO 算法。</li></ul>',16))])}const R=r(d,[["render",g]]);export{F as __pageData,R as default};
